import { test, expect } from '@playwright/test';
import path from 'path';
import { fileURLToPath } from 'url';
const __dirname = path.dirname(fileURLToPath(import.meta.url));
const localUrl = `file://${path.resolve(__dirname, 'target-app/inner.html')}`;
test.describe('Inner Frame Page Tests', () => {
  test.beforeEach(async ({
    page
  }) => {
    await page.goto(localUrl);
  });
  test('should have correct page title and load successfully', async ({
    page
  }) => {
    await expect(page).toHaveTitle('Inner — AutoHeal Demo');
  });
  test('should display frame button and message area correctly', async ({
    page
  }) => {
    const button = page.getByRole('button', {
      name: 'Click in Frame'
    });
    const message = page.locator('#frame-message');
    await expect(button).toBeVisible();
    await expect(message).toHaveText('Waiting for click...');
  });
  test('should update message when frame button is clicked', async ({
    page
  }) => {
    const button = page.getByRole('button', {
      name: 'Click in Frame'
    });
    const message = page.locator('#frame-message');
    await button.click();
    await expect(message).toHaveText('Button in frame clicked!');
  });
});
